 gap: var(--now-static-space--xs, 0.25rem);
 margin-left: var(--now-static-space--sm, 0.5rem);
 margin-top: var(--now-static-space--xs, 0.25rem);
}

.session-card__tag {
 display: inline-block;
 background-color: rgb(var(--now-color_background--secondary, 245,246,247));
 color: rgb(var(--now-color_text--primary, 16,23,26));
 padding: var(--now-static-space--xs, 0.25rem) var(--now-static-space--sm, 0.5rem);
 border-radius: var(--now-static-border-radius--md, 0.25rem);
 font-size: 0.75rem;
 border: 1px solid rgb(var(--now-container--border-color, 207,213,215));
}

/* Responsive design for smaller screens */
@media (max-width: 768px) {
 .session-card__meta {
 grid-template-columns: 1fr;
 gap: var(--now-static-space--sm, 0.5rem);
 }

 .session-card__header {
 flex-direction: column;
 align-items: flex-start;
 }

 .session-list__legend {
 flex-direction: column;
 align-items: flex-start;
 gap: var(--now-static-space--sm, 0.5rem);
 }

 .session-list__legend-items {
 gap: var(--now-static-space--sm, 0.5rem);
 }
}","/* Reset browser defaults */
body, html {
 margin: 0;
 padding: 0;
 box-sizing: border-box;
}

*, *::before, *::after {
 box-sizing: inherit;
}

.app {
 min-height: 100vh;
 padding: var(--now-static-space--lg, 1rem);
 background-color: rgb(var(--now-color_background--primary, 255,255,255));
 color: rgb(var(--now-color_text--primary, 16,23,26));
 font-family: var(--now-font-family, system-ui, sans-serif);
 line-height: var(--now-static-line-height, 1.25);
}

.app__header {
 margin-bottom: var(--now-static-space--xl, 1.5rem);
 text-align: center;
 padding-bottom: var(--now-static-space--lg, 1rem);
 border-bottom: 2px solid rgb(var(--now-container--border-color, 207,213,215));
}

.app__title {
 margin: 0 0 var(--now-static-space--sm, 0.5rem) 0;
 font-size: 2rem;
 font-weight: var(--now-heading--header-primary--font-weight, 600);
 color: rgb(var(--now-heading--header-primary--color, 35,46,51));
}

.app__subtitle {
 margin: 0;
 font-size: 1.125rem;
 color: rgb(var(--now-color_text--secondary, 75,85,89));
 font-weight: 400;
}

.app__content {
 display: grid;
 grid-template-columns: 300px 1fr;
 gap: var(--now-static-space--xl, 1.5rem);
 height: calc(100vh - 200px);
 align-items: start;
}

.app__sidebar {
 position: sticky;
 top: var(--now-static-space--lg, 1rem);
}

.app__main {
 height: 100%;
 overflow: hidden;
}

/* Loading state */
.app__loading {
 display: flex;
 flex-direction: column;
 align-items: center;
 justify-content: center;
 padding: var(--now-static-space--3xl, 2.5rem);
 text-align: center;
}

.loading-spinner {
 width: 2rem;
 height: 2rem;
 border: 3px solid rgb(var(--now-container--border-color, 207,213,215));
 border-top: 3px solid rgb(var(--now-color--primary-1, 0,128,163));
 border-radius: 50%;
 animation: spin 1s linear infinite;
 margin-bottom: var(--now-static-space--lg, 1rem);
}

@keyframes spin {
 0% { transform: rotate(0deg); }
 100% { transform: rotate(360deg); }
}

.app__loading p {
 color: rgb(var(--now-color_text--secondary, 75,85,89));
 margin: 0;
}

/* Error state */
.app__error {
 display: flex;
 flex-direction: column;
 align-items: center;
 justify-content: center;
 padding: var(--now-static-space--3xl, 2.5rem);
 text-align: center;
}

.app__error h2 {
 margin: 0 0 var(--now-static-space--md, 0.75rem) 0;
 color: rgb(var(--now-indicator--primary_critical--background-color, 229,34,57));
}

.app__error p {
 margin: 0 0 var(--now-static-space--lg, 1rem) 0;
 color: rgb(var(--now-color_text--secondary, 75,85,89));
}

/* Primary button for retry */
.btn--primary {
 background-color: rgb(var(--now-actionable--primary--background-color, 0,128,163));
 color: rgb(var(--now-actionable_label--primary--color, 255,255,255));
 border: 1px solid rgb(var(--now-actionable--primary--border-color, 0,128,163));
 border-radius: var(--now-actionable--border-radius, 6px);
 padding: var(--now-static-space--sm, 0.5rem) var(--now-static-space--lg, 1rem);
 font-family: var(--now-font-family, system-ui, sans-serif);
 font-size: 1rem;
 font-weight: 500;
 cursor: pointer;
 transition: background-color 100ms linear;
}

.btn--primary:hover {
 background-color: rgb(var(--now-actionable--primary--background-color--hover, 0,138,173));
}

.btn--primary:active {
 background-color: rgb(var(--now-actionable--primary--background-color--active, 0,108,143));
}

.btn--primary:focus-visible {
 box-shadow: inset 0 0 0 2px rgb(var(--now-color_focus-ring_shadow, 53,147,37));
}

/* Responsive design */
@media (max-width: 1024px) {
 .app__content {
 grid-template-columns: 1fr;
 gap: var(--now-static-space--lg, 1rem);
 height: auto;
 }

 .app__sidebar {
 position: relative;
 top: auto;
 }

 .app__main {
 height: 60vh;
 min-height: 400px;
 }
}

@media (max-width: 768px) {
 .app {
 padding: var(--now-static-space--md, 0.75rem);
 }

 .app__title {
 font-size: 1.75rem;
 }

 .app__subtitle {
 font-size: 1rem;
 }

 .app__content {
 gap: var(--now-static-space--md, 0.75rem);
 }
}","import React from 'react';
